For comparison, this is what your example would look like in full:
```python
batcher = Batcher(batch_size=batch_size)
for block_window in window(self._blocks, prefetch_blocks + 1):
    block_window = list(block_window)
    ray.wait(block_window, num_returns=1, fetch_local=False)
    block = ray.get(block_window[0])
    batcher.add(block)
    while batcher.has_batch():
        yield format(batcher.next_batch(), batch_format)

if batcher.has_remainder_batch() and not drop_last:
   yield format(batcher.get_remainder_batch())


class Batcher:
    def __init__(self, batch_size):
        self.batch_size = batch_size
        self.buffer = []

    def add(self, batch):
        self.buffer.append(batch)

    def has_batch(self):
        return sum(b.num_rows() for b in self.buffer) >= self.batch_size

    def has_any(self):
        return any(b.num_rows() > 0 for b in self.buffer)

    def next_batch(self):
        if self.batch_size is None:
            return concat(self.buffer)
        output = DelegatingArrowBlockBuilder()
        leftover = []
        needed = self.batch_size
        for b in self.buffer:
            if needed <= 0:
                # Don't need
                leftover.append(b)
            elif b.num_rows() <= needed:
                # Need the entire batch
                output.add_block(b)
                needed -= b.num_rows()
            else:
                # Need the partial batch
                output.add_block(b.slice(0, needed, copy=False))
                leftover.append(b.slice(needed, b.num_rows(), copy=False))
                needed = 0

        self.buffer = leftover
        return output.build()
```

We could implement something similar for Python 3.6 via a "replace module with class hack":
```python
class module(types.ModuleType):
    __all__ = __all__

    def __init__(self, orig_module: types.ModuleType):
        self._orig_module = orig_module

    def __getattr__(self, name: str):
        try:
            return getattr(name, self._orig_module)
        except AttributeError as e:
            if name in _subpackages:
                return importlib.import_module("." + name, self._orig_module.__name__)
            raise e from None


sys.modules[__name__] = module(sys.modules[__name__])
```

But IMO this is more hacky than its worth since we're going to be dropping Python 3.6 support in the near-term.

